CREATE TRIGGER handle_message_reactions_change AFTER INSERT OR DELETE OR UPDATE ON public.message_reactions FOR EACH ROW EXECUTE FUNCTION public.message_reactions_broadcast();

CREATE TRIGGER handle_messages_change AFTER INSERT OR DELETE OR UPDATE ON public.messages FOR EACH ROW EXECUTE FUNCTION public.messages_broadcast();

CREATE TRIGGER handle_room_user_read_update AFTER UPDATE ON public.room_user FOR EACH ROW EXECUTE FUNCTION public.room_user_read_broadcast();


